public struct ExportManager {
    /// Export the current spiral as a PNG image
    @available(macOS 14.0, iOS 17.0, *)
    public static func exportAsPNG(
        viewModel: SpiralViewModel,
        size: CGSize = CGSize(width: 2048, height: 2048)
    ) async throws -> Data {
        let renderer = ImageRenderer(content: ExportableCanvas(viewModel: viewModel, size: size))
        renderer.scale = 2.0  // Retina
        #if os(macOS)
        guard let nsImage = renderer.nsImage else {
            throw ExportError.renderingFailed
        }
        guard let tiffData = nsImage.tiffRepresentation,
              let bitmap = NSBitmapImageRep(data: tiffData) else {
            throw ExportError.imageConversionFailed
        }
        guard let pngData = bitmap.representation(using: .png, properties: [:]) else {
            throw ExportError.pngEncodingFailed
        }
        return pngData
        #else
        guard let uiImage = renderer.uiImage else {
            throw ExportError.renderingFailed
        }
        guard let pngData = uiImage.pngData() else {
            throw ExportError.pngEncodingFailed
        }
        return pngData
        #endif
    }
    /// Save PNG to the user's chosen location (macOS)
    #if os(macOS)
    public static func savePNG(data: Data, filename: String = "uzumaki-spiral.png") async throws {
        let savePanel = NSSavePanel()
        savePanel.allowedContentTypes = [.png]
        savePanel.nameFieldStringValue = filename
        savePanel.canCreateDirectories = true
        let result = await savePanel.begin()
        guard result == .OK, let url = savePanel.url else {
            throw ExportError.saveCancelled
        }
        do {
            try data.write(to: url)
        } catch {
            throw ExportError.saveFailed(error)
        }
    }
    /// Share PNG using system share sheet (macOS)
    public static func share(data: Data, from view: NSView? = nil) {
        guard let image = NSImage(data: data) else { return }
        guard let window = NSApp.keyWindow,
              let contentView = view ?? window.contentView else {
            return
        }
        let picker = NSSharingServicePicker(items: [image])
        let rect = CGRect(
            x: contentView.bounds.midX,
            y: contentView.bounds.midY,
            width: 1,
            height: 1
        )
        picker.show(relativeTo: rect, of: contentView, preferredEdge: .minY)
    }
    #endif
    /// Result of a save to photos operation
    public enum SaveResult {
        case success
        case permissionDenied
        case failed(Error?)
    }
    /// Save PNG to Photos library (iOS)
    #if os(iOS)
    public static func saveToPhotos(data: Data) async -> SaveResult {
        guard let image = UIImage(data: data) else { return .failed(nil) }
        return await withCheckedContinuation { continuation in
            PHPhotoLibrary.requestAuthorization(for: .addOnly) { status in
                guard status == .authorized || status == .limited else {
                    continuation.resume(returning: .permissionDenied)
                    return
                }
                PHPhotoLibrary.shared().performChanges {
                    PHAssetCreationRequest.creationRequestForAsset(from: image)
                } completionHandler: { success, error in
                    if success {
                        continuation.resume(returning: .success)
                    } else {
                        continuation.resume(returning: .failed(error))
                    }
                }
            }
        }
    }
    /// Open the Settings app to the app's settings page
    public static func openSettings() {
        if let settingsURL = URL(string: UIApplication.openSettingsURLString) {
            UIApplication.shared.open(settingsURL)
        }
    }
    /// Share PNG using system share sheet (iOS)
    public static func share(data: Data, from sourceView: UIView? = nil) {
        guard let image = UIImage(data: data) else { return }
        let activityVC = UIActivityViewController(
            activityItems: [image],
            applicationActivities: nil
        )
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let rootVC = windowScene.windows.first?.rootViewController else {
            return
        }
        if let popover = activityVC.popoverPresentationController {
            popover.sourceView = sourceView ?? rootVC.view
            popover.sourceRect = sourceView?.bounds ?? CGRect(x: rootVC.view.bounds.midX, y: rootVC.view.bounds.midY, width: 0, height: 0)
        }
        rootVC.present(activityVC, animated: true)
    }
    #endif
}

extension View {
    /// Applies an adaptive glass effect that uses Liquid Glass on iOS 26+ or falls back to materials
    @ViewBuilder
    func adaptiveGlassEffect<S: Shape>(
        in shape: S,
        interactive: Bool = false
    ) -> some View {
        if #available(iOS 26.0, macOS 26.0, watchOS 26.0, tvOS 26.0, *) {
            let glass = interactive ? Glass.regular.interactive() : .regular
            self.glassEffect(glass, in: shape)
        } else {
            self
                .background(shape.fill(.ultraThinMaterial))
                .clipShape(shape)
        }
    }
    /// Applies a capsule-shaped glass effect
    @ViewBuilder
    func adaptiveGlassCapsule(interactive: Bool = false) -> some View {
        adaptiveGlassEffect(in: Capsule(), interactive: interactive)
    }
    /// Applies a rounded rectangle glass effect
    @ViewBuilder
    func adaptiveGlassRoundedRect(cornerRadius: CGFloat = 16, interactive: Bool = false) -> some View {
        adaptiveGlassEffect(in: RoundedRectangle(cornerRadius: cornerRadius), interactive: interactive)
    }
    /// Applies a tinted glass effect (iOS 26+ only, falls back to tinted material)
    @ViewBuilder
    func adaptiveTintedGlass<S: Shape>(
        _ tintColor: Color,
        in shape: S,
        interactive: Bool = false
    ) -> some View {
        if #available(iOS 26.0, macOS 26.0, watchOS 26.0, tvOS 26.0, *) {
            let baseGlass = interactive ? Glass.regular.interactive() : .regular
            self.glassEffect(baseGlass.tint(tintColor), in: shape)
        } else {
            self
                .background(
                    shape
                        .fill(.ultraThinMaterial)
                        .overlay(shape.fill(tintColor.opacity(0.15)))
                )
                .clipShape(shape)
        }
    }
}

