public enum SpiralMeshGenerator {
    /// Default tube radius for spiral mesh (in meters)
    public static let defaultTubeRadius: Float = 0.005
    /// Number of segments around the tube circumference
    public static let tubeSegments: Int = 16
    /// Thread-safe cache storage using actor
    private static let meshCache = MeshCache()
    /// Clear the mesh cache
    public static func clearCache() async {
        await meshCache.clear()
    }
    /// Generate a tube mesh from spiral parameters with gradient colors (cached, async)
    /// - Parameters:
    ///   - params: The 3D spiral parameters
    ///   - colors: SwiftUI colors for gradient
    /// - Returns: A MeshResource with vertex colors for gradient
    public static func generateCachedMesh(
        params: SpiralParams3D,
        colors: [SwiftUI.Color]
    ) async throws -> MeshResource {
        let cacheKey = MeshCacheKey(
            paramsHash: params.hashValue,
            colorsHash: colors.map { $0.hashValue }.reduce(0, ^)
        )
        if let cached = await meshCache.get(cacheKey) {
            return cached
        }
        let points3D = SpiralGenerator3D.generate(params: params)
        let gradient = createGradient(from: colors)
        let meshData = try TubeMeshGenerator.generate(
            from: points3D,
            gradient: gradient,
            tubeRadius: params.tubeRadius,
            tubeSegments: tubeSegments
        )
        let mesh = try createMeshResource(from: meshData)
        await meshCache.set(cacheKey, mesh: mesh)
        return mesh
    }
    /// Generate mesh asynchronously on a background thread
    /// - Parameters:
    ///   - params: The 3D spiral parameters
    ///   - colors: SwiftUI colors for gradient
    /// - Returns: A MeshResource with vertex colors for gradient
    public static func generateCachedMeshAsync(
        params: SpiralParams3D,
        colors: [SwiftUI.Color]
    ) async throws -> MeshResource {
        let cacheKey = MeshCacheKey(
            paramsHash: params.hashValue,
            colorsHash: colors.map { $0.hashValue }.reduce(0, ^)
        )
        if let cached = await meshCache.get(cacheKey) {
            return cached
        }
        let meshData = try await Task.detached(priority: .userInitiated) {
            let points3D = SpiralGenerator3D.generate(params: params)
            let gradient = createGradient(from: colors)
            return try TubeMeshGenerator.generate(
                from: points3D,
                gradient: gradient,
                tubeRadius: params.tubeRadius,
                tubeSegments: tubeSegments
            )
        }.value
        let mesh = try await MainActor.run {
            try createMeshResource(from: meshData)
        }
        await meshCache.set(cacheKey, mesh: mesh)
        return mesh
    }
    /// Generate a tube mesh from 3D spiral points (legacy, no caching)
    /// - Parameters:
    ///   - points: The 3D spiral points to create a tube around
    ///   - tubeRadius: Radius of the tube in meters
    ///   - addEndCaps: Whether to add end caps to close the tube
    /// - Returns: A MeshResource representing the spiral as a tube
    public static func generateTubeMesh(
        from points: SpiralPoints3D,
        tubeRadius: Float = defaultTubeRadius,
        addEndCaps: Bool = true
    ) throws -> MeshResource {
        guard points.count >= 2 else {
            throw MeshGenerationError.insufficientPoints
        }
        let gradient = UzumakiCore.Gradient(colors: [GradientColor(r: 1, g: 1, b: 1)])
        let meshData = try TubeMeshGenerator.generate(
            from: points,
            gradient: gradient,
            tubeRadius: tubeRadius,
            tubeSegments: tubeSegments,
            addEndCaps: addEndCaps
        )
        return try createMeshResource(from: meshData)
    }
    /// Generate a tube mesh with gradient colors
    /// - Parameters:
    ///   - points: The 3D spiral points
    ///   - colors: SwiftUI colors for gradient
    ///   - tubeRadius: Radius of the tube in meters
    /// - Returns: A MeshResource with vertex colors
    public static func generateTubeMeshWithGradient(
        from points: SpiralPoints3D,
        colors: [SwiftUI.Color],
        tubeRadius: Float = defaultTubeRadius
    ) throws -> MeshResource {
        guard points.count >= 2 else {
            throw MeshGenerationError.insufficientPoints
        }
        let gradient = createGradient(from: colors)
        let meshData = try TubeMeshGenerator.generate(
            from: points,
            gradient: gradient,
            tubeRadius: tubeRadius,
            tubeSegments: tubeSegments
        )
        return try createMeshResource(from: meshData)
    }
    private static func createGradient(from colors: [SwiftUI.Color]) -> UzumakiCore.Gradient {
        let gradientColors = colors.map { color -> GradientColor in
            let uiColor = UIColor(color)
            var r: CGFloat = 0, g: CGFloat = 0, b: CGFloat = 0, a: CGFloat = 0
            uiColor.getRed(&r, green: &g, blue: &b, alpha: &a)
            return GradientColor(r: Float(r), g: Float(g), b: Float(b), a: Float(a))
        }
        return UzumakiCore.Gradient(colors: gradientColors.isEmpty
            ? [GradientColor(r: 1, g: 1, b: 1)]
            : gradientColors)
    }
    private static func createMeshResource(from meshData: SpiralMeshData) throws -> MeshResource {
        var descriptor = MeshDescriptor(name: "SpiralTube")
        descriptor.positions = MeshBuffer(meshData.positions)
        descriptor.normals = MeshBuffer(meshData.normals)
        descriptor.textureCoordinates = MeshBuffer(meshData.uvs)
        descriptor.primitives = .triangles(meshData.indices)
        return try MeshResource.generate(from: [descriptor])
    }
}

public enum SpiralRenderer {
    /// Creates a Path from spiral points centered at the given point
    public static func createPath(points: SpiralPoints, center: CGPoint) -> Path {
        var path = Path()
        guard points.count > 0 else { return path }
        path.move(to: CGPoint(
            x: center.x + CGFloat(points.x(at: 0)),
            y: center.y + CGFloat(points.y(at: 0))
        ))
        for i in 1..<points.count {
            path.addLine(to: CGPoint(
                x: center.x + CGFloat(points.x(at: i)),
                y: center.y + CGFloat(points.y(at: i))
            ))
        }
        return path
    }
    /// Draw spiral as a gradient line
    public static func drawLine(
        context: GraphicsContext,
        points: SpiralPoints,
        center: CGPoint,
        colors: [Color],
        lineStyle: LineStyle
    ) {
        guard points.count > 1 else { return }
        let path = createPath(points: points, center: center)
        let gradient = Gradient(colors: colors)
        var strokeStyle = StrokeStyle(
            lineWidth: Constants.lineWidthDefault,
            lineCap: .round,
            lineJoin: .round
        )
        let dash = lineStyle.dashPattern
        if !dash.isEmpty {
            strokeStyle.dash = dash
        }
        context.stroke(path, with: .linearGradient(
            gradient,
            startPoint: CGPoint(x: center.x - 200, y: center.y - 200),
            endPoint: CGPoint(x: center.x + 200, y: center.y + 200)
        ), style: strokeStyle)
    }
    /// Draw spiral as individual colored points
    public static func drawPoints(
        context: GraphicsContext,
        points: SpiralPoints,
        center: CGPoint,
        colors: [Color],
        zoom: Double
    ) {
        let pointRadius = max(Constants.pointRadiusMin, Constants.pointRadiusBase * zoom)
        for i in 0..<points.count {
            let progress = Double(i) / Double(max(1, points.count - 1))
            let colorIndex = Int(progress * Double(colors.count - 1))
            let color = colors[min(colorIndex, colors.count - 1)]
            let point = CGPoint(
                x: center.x + CGFloat(points.x(at: i)),
                y: center.y + CGFloat(points.y(at: i))
            )
            let rect = CGRect(
                x: point.x - pointRadius,
                y: point.y - pointRadius,
                width: pointRadius * 2,
                height: pointRadius * 2
            )
            context.fill(Circle().path(in: rect), with: .color(color))
        }
    }
    /// Draw spiral as triangles emanating from origin
    public static func drawTriangles(
        context: GraphicsContext,
        points: SpiralPoints,
        center: CGPoint,
        colors: [Color]
    ) {
        guard points.count > 1 else { return }
        let origin = CGPoint(
            x: center.x + CGFloat(points.x(at: 0)),
            y: center.y + CGFloat(points.y(at: 0))
        )
        for i in 1..<points.count {
            let progress = Double(i) / Double(points.count)
            let colorIndex = Int(progress * Double(colors.count - 1))
            let color = colors[min(colorIndex, colors.count - 1)]
            var path = Path()
            path.move(to: origin)
            if i > 1 {
                path.addLine(to: CGPoint(
                    x: center.x + CGFloat(points.x(at: i - 1)),
                    y: center.y + CGFloat(points.y(at: i - 1))
                ))
            }
            path.addLine(to: CGPoint(
                x: center.x + CGFloat(points.x(at: i)),
                y: center.y + CGFloat(points.y(at: i))
            ))
            path.addLine(to: origin)
            context.stroke(path, with: .color(color), style: StrokeStyle(
                lineWidth: Constants.lineWidthTriangles,
                lineCap: .round,
                lineJoin: .round
            ))
        }
    }
    /// Draw glow effect around the spiral path
    public static func drawGlow(
        context: GraphicsContext,
        points: SpiralPoints,
        center: CGPoint,
        glowColor: Color,
        performanceMode: Bool,
        glowOnly: Bool
    ) {
        guard points.count > 1 else { return }
        let path = createPath(points: points, center: center)
        let layers = performanceMode
            ? Constants.glowLayersPerformance
            : Constants.glowLayersNormal
        for layer in layers {
            let opacity = glowOnly ? layer.opacity * 2 : layer.opacity
            let width = glowOnly ? layer.width * 1.5 : layer.width
            context.stroke(path, with: .color(glowColor.opacity(opacity)), style: StrokeStyle(
                lineWidth: width,
                lineCap: .round,
                lineJoin: .round
            ))
        }
    }
}

public final class UserSettings {
    public static let shared = UserSettings()
    private init() {}
    private enum Keys {
        static let spiralType = "spiralType"
        static let colorPreset = "colorPreset"
        static let lineStyle = "lineStyle"
        static let backgroundTheme = "backgroundTheme"
        static let performanceMode = "performanceMode"
        static let lineThicknessVariation = "lineThicknessVariation"
        static let spinRate = "spinRate"
        static let tightness = "tightness"
        static let stepSize = "stepSize"
        static let numSteps = "numSteps"
        static let hasLaunchedBefore = "hasLaunchedBefore"
    }
    private var defaults: UserDefaults { .standard }
    public var hasLaunchedBefore: Bool {
        get { defaults.bool(forKey: Keys.hasLaunchedBefore) }
        set { defaults.set(newValue, forKey: Keys.hasLaunchedBefore) }
    }
    public var spiralType: SpiralType {
        get {
            guard let raw = defaults.string(forKey: Keys.spiralType),
                  let type = SpiralType(rawValue: raw) else {
                return .archimedean
            }
            return type
        }
        set { defaults.set(newValue.rawValue, forKey: Keys.spiralType) }
    }
    public var colorPreset: ColorPreset {
        get {
            guard let raw = defaults.string(forKey: Keys.colorPreset),
                  let preset = ColorPreset(rawValue: raw) else {
                return .rainbow
            }
            return preset
        }
        set { defaults.set(newValue.rawValue, forKey: Keys.colorPreset) }
    }
    public var lineStyle: LineStyle {
        get {
            guard let raw = defaults.string(forKey: Keys.lineStyle),
                  let style = LineStyle(rawValue: raw) else {
                return .solid
            }
            return style
        }
        set { defaults.set(newValue.rawValue, forKey: Keys.lineStyle) }
    }
    public var backgroundTheme: BackgroundTheme {
        get {
            guard let raw = defaults.string(forKey: Keys.backgroundTheme),
                  let theme = BackgroundTheme(rawValue: raw) else {
                return .dark
            }
            return theme
        }
        set { defaults.set(newValue.rawValue, forKey: Keys.backgroundTheme) }
    }
    public var performanceMode: Bool {
        get { defaults.bool(forKey: Keys.performanceMode) }
        set { defaults.set(newValue, forKey: Keys.performanceMode) }
    }
    public var lineThicknessVariation: Bool {
        get { defaults.bool(forKey: Keys.lineThicknessVariation) }
        set { defaults.set(newValue, forKey: Keys.lineThicknessVariation) }
    }
    public var spinRate: Double {
        get {
            let value = defaults.double(forKey: Keys.spinRate)
            return value == 0 ? 0.5 : value  // Default to 0.5 if not set
        }
        set { defaults.set(newValue, forKey: Keys.spinRate) }
    }
    public var tightness: Double {
        get {
            let value = defaults.double(forKey: Keys.tightness)
            return value == 0 ? 3.0 : value  // Default to 3.0 if not set
        }
        set { defaults.set(newValue, forKey: Keys.tightness) }
    }
    public var stepSize: Double {
        get {
            let value = defaults.double(forKey: Keys.stepSize)
            return value == 0 ? 0.1 : value  // Default to 0.1 if not set
        }
        set { defaults.set(newValue, forKey: Keys.stepSize) }
    }
    public var numSteps: Int {
        get {
            let value = defaults.integer(forKey: Keys.numSteps)
            return value == 0 ? 500 : value  // Default to 500 if not set
        }
        set { defaults.set(newValue, forKey: Keys.numSteps) }
    }
}

