public final class SpiralViewModel {
    public var spiralType: SpiralType = .archimedean {
        didSet {
            zoom = spiralType.defaultZoom
            panX = 0
            panY = 0
            triggerSelectionFeedback()
            saveSettings()
        }
    }
    public var spinRate: Double = 0.5 {
        didSet { saveSettings() }
    }
    public var tightness: Double = 3.0 {
        didSet { saveSettings() }
    }
    public var stepSize: Double = 0.1 {
        didSet { saveSettings() }
    }
    public var numSteps: Int = 500 {
        didSet { saveSettings() }
    }
    public var colorPreset: ColorPreset = .rainbow {
        didSet { saveSettings() }
    }
    public var lineStyle: LineStyle = .solid {
        didSet { saveSettings() }
    }
    public var backgroundTheme: BackgroundTheme = .dark {
        didSet { saveSettings() }
    }
    public var performanceMode: Bool = false {
        didSet { saveSettings() }
    }
    public var lineThicknessVariation: Bool = false {
        didSet { saveSettings() }
    }
    public var zoom: Double = 1.0
    public var panX: Double = 0
    public var panY: Double = 0
    public var time: Double = 0
    public var isPaused: Bool = false
    public var viewportScale: Double = 1.0
    public var fps: Int = 0
    private var frameCount: Int = 0
    private var lastFPSUpdate: Double = 0
    private var cachedSpiralPoints: SpiralPoints?
    private var cachedSpiralParamsHash: Int = 0
    public var showOnboarding: Bool = true
    public var showShortcuts: Bool = false
    public var toastMessage: String?
    /// Current parameters as a struct for spiral generation
    public var params: SpiralParams {
        SpiralParams(
            type: spiralType,
            tightness: tightness,
            spinRate: spinRate,
            stepSize: stepSize,
            numSteps: numSteps,
            time: time,
            viewportScale: viewportScale,
            zoom: zoom,
            panX: panX,
            panY: panY,
            colorPreset: colorPreset,
            lineStyle: lineStyle,
            backgroundTheme: backgroundTheme,
            performanceMode: performanceMode,
            lineThicknessVariation: lineThicknessVariation,
            isPaused: isPaused
        )
    }
    /// Generate spiral points for current parameters (cached for performance)
    public var spiralPoints: SpiralPoints {
        let currentHash = spiralParamsHash
        if let cached = cachedSpiralPoints, cachedSpiralParamsHash == currentHash {
            return cached
        }
        let points = SpiralGenerator.generate(params: params)
        cachedSpiralPoints = points
        cachedSpiralParamsHash = currentHash
        return points
    }
    /// Hash of parameters that affect spiral geometry (excludes pan/zoom/isPaused)
    private var spiralParamsHash: Int {
        var hasher = Hasher()
        hasher.combine(spiralType)
        hasher.combine(tightness)
        hasher.combine(spinRate)
        hasher.combine(stepSize)
        hasher.combine(numSteps)
        hasher.combine(time)
        hasher.combine(viewportScale)
        hasher.combine(zoom)
        hasher.combine(panX)
        hasher.combine(panY)
        return hasher.finalize()
    }
    /// Colors for the current preset
    public var colors: [Color] {
        colorPreset.colors
    }
    /// Glow color (third color or first)
    public var glowColor: Color {
        colors.count > 2 ? colors[2] : colors[0]
    }
    /// Background color based on style and color preset
    public var backgroundColor: Color {
        if backgroundTheme == .matching {
            return colors[0].opacity(0.13)
        }
        return backgroundTheme.baseColor
    }
    public init() {
        loadSettings()
    }
    /// Flag to prevent saving while loading
    private var isLoadingSettings = false
    /// Check if app is launched in screenshot mode (should reset to defaults)
    private var isScreenshotMode: Bool {
        ProcessInfo.processInfo.arguments.contains("-RESET_FOR_SCREENSHOTS")
    }
    /// Load saved settings from UserDefaults
    private func loadSettings() {
        if isScreenshotMode {
            return
        }
        isLoadingSettings = true
        defer { isLoadingSettings = false }
        let settings = UserSettings.shared
        guard settings.hasLaunchedBefore else {
            settings.hasLaunchedBefore = true
            return
        }
        spiralType = settings.spiralType
        colorPreset = settings.colorPreset
        lineStyle = settings.lineStyle
        backgroundTheme = settings.backgroundTheme
        performanceMode = settings.performanceMode
        lineThicknessVariation = settings.lineThicknessVariation
        spinRate = settings.spinRate
        tightness = settings.tightness
        stepSize = settings.stepSize
        numSteps = settings.numSteps
        zoom = spiralType.defaultZoom
    }
    /// Save current settings to UserDefaults
    private func saveSettings() {
        guard !isLoadingSettings, !isScreenshotMode else { return }
        let settings = UserSettings.shared
        settings.spiralType = spiralType
        settings.colorPreset = colorPreset
        settings.lineStyle = lineStyle
        settings.backgroundTheme = backgroundTheme
        settings.performanceMode = performanceMode
        settings.lineThicknessVariation = lineThicknessVariation
        settings.spinRate = spinRate
        settings.tightness = tightness
        settings.stepSize = stepSize
        settings.numSteps = numSteps
    }
    /// Toggle play/pause
    public func togglePause() {
        isPaused.toggle()
        triggerImpactFeedback(style: .light)
    }
    /// Reset to default values
    public func reset() {
        spiralType = .archimedean
        spinRate = 0.5
        tightness = 3.0
        stepSize = 0.1
        numSteps = 500
        colorPreset = .rainbow
        lineStyle = .solid
        backgroundTheme = .dark
        performanceMode = false
        lineThicknessVariation = false
        zoom = spiralType.defaultZoom
        panX = 0
        panY = 0
        time = 0
        isPaused = false
        triggerImpactFeedback(style: .medium)
    }
    /// Load a preset
    public func loadPreset(_ preset: SpiralPreset) {
        spiralType = preset.type
        tightness = preset.tightness
        spinRate = preset.spinRate
        stepSize = preset.stepSize
        numSteps = preset.numSteps
        colorPreset = preset.colorPreset
        lineStyle = preset.lineStyle
        zoom = preset.zoom
        panX = 0
        panY = 0
    }
    /// Increment time for animation
    public func incrementTime(delta: Double) {
        frameCount += 1
        lastFPSUpdate += delta
        if lastFPSUpdate >= 1.0 {
            fps = frameCount
            frameCount = 0
            lastFPSUpdate = 0
        }
        guard !isPaused else { return }
        time += delta
    }
    /// Adjust spin rate within bounds
    public func adjustSpinRate(by delta: Double) {
        spinRate = max(Constants.spinRateMin, min(Constants.spinRateMax, spinRate + delta))
    }
    /// Show a toast message (auto-dismisses after timeout)
    public func showToast(_ message: String) {
        toastMessage = message
        Task { @MainActor in
            try? await Task.sleep(for: .seconds(Constants.toastDurationSeconds))
            if toastMessage == message {
                withAnimation {
                    toastMessage = nil
                }
            }
        }
    }
    /// Dismiss the toast immediately
    public func dismissToast() {
        withAnimation {
            toastMessage = nil
        }
    }
    /// Update viewport scale based on canvas size
    public func updateViewportScale(for size: CGSize) {
        let minDimension = min(size.width, size.height)
        let scale = max(
            Constants.viewportScaleMin,
            min(Constants.viewportScaleMax, minDimension / Constants.viewportBaseSize)
        )
        viewportScale = scale
    }
    /// Trigger selection changed haptic (for picker changes)
    public func triggerSelectionFeedback() {
        #if os(iOS)
        let generator = UISelectionFeedbackGenerator()
        generator.selectionChanged()
        #endif
    }
    /// Trigger impact haptic (for button taps)
    public func triggerImpactFeedback(style: ImpactStyle = .light) {
        #if os(iOS)
        let generator = UIImpactFeedbackGenerator(style: style.uiKitStyle)
        generator.impactOccurred()
        #endif
    }
    /// Trigger success haptic (for completed actions)
    public func triggerSuccessFeedback() {
        #if os(iOS)
        let generator = UINotificationFeedbackGenerator()
        generator.notificationOccurred(.success)
        #endif
    }
}

public final class TVSpiralViewModel {
    public var spiralType: SpiralType = .archimedean {
        didSet {
            zoom = spiralType.defaultZoom
            invalidateCachedPoints()
        }
    }
    public var spinRate: Double = 0.5 {
        didSet { invalidateCachedPoints() }
    }
    public var tightness: Double = 3.0 {
        didSet { invalidateCachedPoints() }
    }
    public var stepSize: Double = 0.1 {
        didSet { invalidateCachedPoints() }
    }
    private var baseNumSteps: Int = 800 {
        didSet { invalidateCachedPoints() }
    }
    /// Effective number of steps (respects high quality mode)
    public var numSteps: Int {
        get { highQualityMode ? baseNumSteps : min(baseNumSteps, Constants.numStepsPerformanceMax) }
        set { baseNumSteps = newValue }
    }
    public var colorPreset: ColorPreset = .rainbow
    public var lineStyle: LineStyle = .solid
    public var zoom: Double = 1.0 {
        didSet { invalidateCachedPoints() }
    }
    public var time: Double = 0
    public var isPaused: Bool = false
    private let viewportScale: Double = 1.2
    public var showingSettings: Bool = false
    public var showingPresets: Bool = false
    /// When enabled, uses full detail. When disabled, limits to 500 points for smoother performance.
    /// Defaults to enabled on high-performance devices (Apple TV 4K).
    public var highQualityMode: Bool = TVSpiralViewModel.detectHighPerformanceDevice() {
        didSet { invalidateCachedPoints() }
    }
    /// Detects if device is high-performance (Apple TV 4K vs HD)
    private static func detectHighPerformanceDevice() -> Bool {
        var size = 0
        sysctlbyname("hw.machine", nil, &size, nil, 0)
        var machine = [CChar](repeating: 0, count: size)
        sysctlbyname("hw.machine", &machine, &size, nil, 0)
        let model = String(cString: machine)
        return model.contains("AppleTV6") || model.contains("AppleTV11") || model.contains("AppleTV14")
    }
    /// When enabled, reduces brightness after extended viewing periods
    public var dimModeEnabled: Bool = false
    /// Current brightness multiplier (0.0 to 1.0)
    public private(set) var currentBrightness: Double = 1.0
    /// Time in seconds before dimming starts
    public var dimModeDelaySeconds: Double = 300 // 5 minutes
    /// Target brightness when dimmed (0.0 to 1.0)
    public var dimModeBrightness: Double = 0.5
    /// Tracks total viewing time for dim mode
    private var viewingStartTime: Date = Date()
    /// Whether currently in dimmed state
    public private(set) var isDimmed: Bool = false
    /// When enabled, automatically cycles through presets
    public var autoCycleEnabled: Bool = false {
        didSet {
            if autoCycleEnabled {
                startAutoCycle()
            } else {
                stopAutoCycle()
            }
        }
    }
    /// Interval in seconds between preset changes
    public var autoCycleIntervalSeconds: Double = 30
    /// Current preset index for auto-cycling
    private var currentPresetIndex: Int = 0
    /// Task for auto-cycling
    private var autoCycleTask: Task<Void, Never>?
    public private(set) var fps: Int = 0
    private var frameCount: Int = 0
    private var lastFPSUpdate: Date = Date()
    private var cachedPoints: SpiralPoints?
    private var cachedTime: Double = -1
    private var needsPointsUpdate: Bool = true
    /// Current parameters as a struct for spiral generation
    public var params: SpiralParams {
        SpiralParams(
            type: spiralType,
            tightness: tightness,
            spinRate: spinRate,
            stepSize: stepSize,
            numSteps: numSteps,
            time: time,
            viewportScale: viewportScale,
            zoom: zoom,
            panX: 0,
            panY: 0,
            colorPreset: colorPreset,
            lineStyle: lineStyle,
            backgroundTheme: .dark,
            performanceMode: !highQualityMode,
            lineThicknessVariation: false,
            isPaused: isPaused
        )
    }
    /// Generate or return cached spiral points for current parameters
    public var spiralPoints: SpiralPoints {
        if needsPointsUpdate || cachedTime != time {
            cachedPoints = SpiralGenerator.generate(params: params)
            cachedTime = time
            needsPointsUpdate = false
        }
        return cachedPoints ?? SpiralPoints(capacity: 0)
    }
    /// Colors for the current preset
    public var colors: [Color] {
        colorPreset.colors
    }
    /// Glow color
    public var glowColor: Color {
        colors.count > 2 ? colors[2] : colors[0]
    }
    /// Background color
    public var backgroundColor: Color {
        Color.black
    }
    public init() {}
    private func invalidateCachedPoints() {
        needsPointsUpdate = true
    }
    /// Update FPS counter - call this each frame
    public func updateFPS() {
        frameCount += 1
        let now = Date()
        let elapsed = now.timeIntervalSince(lastFPSUpdate)
        if elapsed >= 1.0 {
            fps = Int(Double(frameCount) / elapsed)
            frameCount = 0
            lastFPSUpdate = now
        }
    }
    /// Toggle play/pause
    public func togglePause() {
        isPaused.toggle()
    }
    /// Cycle to next spiral type
    public func nextSpiralType() {
        let allTypes = SpiralType.allCases
        if let currentIndex = allTypes.firstIndex(of: spiralType) {
            let nextIndex = (currentIndex + 1) % allTypes.count
            spiralType = allTypes[nextIndex]
        }
    }
    /// Cycle to previous spiral type
    public func previousSpiralType() {
        let allTypes = SpiralType.allCases
        if let currentIndex = allTypes.firstIndex(of: spiralType) {
            let previousIndex = (currentIndex - 1 + allTypes.count) % allTypes.count
            spiralType = allTypes[previousIndex]
        }
    }
    /// Cycle to next color preset
    public func nextColorPreset() {
        let allPresets = ColorPreset.allCases
        if let currentIndex = allPresets.firstIndex(of: colorPreset) {
            let nextIndex = (currentIndex + 1) % allPresets.count
            colorPreset = allPresets[nextIndex]
        }
    }
    /// Cycle to previous color preset
    public func previousColorPreset() {
        let allPresets = ColorPreset.allCases
        if let currentIndex = allPresets.firstIndex(of: colorPreset) {
            let previousIndex = (currentIndex - 1 + allPresets.count) % allPresets.count
            colorPreset = allPresets[previousIndex]
        }
    }
    /// Cycle to next line style
    public func nextLineStyle() {
        let allStyles = LineStyle.allCases
        if let currentIndex = allStyles.firstIndex(of: lineStyle) {
            let nextIndex = (currentIndex + 1) % allStyles.count
            lineStyle = allStyles[nextIndex]
        }
    }
    /// Adjust zoom
    public func adjustZoom(by delta: Double) {
        zoom = max(0.5, min(5.0, zoom + delta))
    }
    /// Adjust spin rate
    public func adjustSpinRate(by delta: Double) {
        spinRate = max(0.1, min(2.0, spinRate + delta))
    }
    /// Adjust tightness
    public func adjustTightness(by delta: Double) {
        tightness = max(Constants.tightnessMin, min(Constants.tightnessMax, tightness + delta))
        invalidateCachedPoints()
    }
    /// Load a preset
    public func loadPreset(_ preset: SpiralPreset) {
        spiralType = preset.type
        tightness = preset.tightness
        spinRate = preset.spinRate
        stepSize = preset.stepSize
        baseNumSteps = min(preset.numSteps, 1000)
        colorPreset = preset.colorPreset
        lineStyle = preset.lineStyle
        zoom = preset.zoom
        invalidateCachedPoints()
    }
    /// Increment time for animation
    public func incrementTime(delta: Double) {
        guard !isPaused else { return }
        time += delta
        updateDimMode()
    }
    /// Reset to defaults
    public func reset() {
        spiralType = .archimedean
        spinRate = 0.5
        tightness = 3.0
        stepSize = 0.1
        baseNumSteps = 800
        colorPreset = .rainbow
        lineStyle = .solid
        zoom = spiralType.defaultZoom
        time = 0
        isPaused = false
        highQualityMode = TVSpiralViewModel.detectHighPerformanceDevice()
        dimModeEnabled = false
        autoCycleEnabled = false
        resetDimMode()
        invalidateCachedPoints()
    }
    /// Start auto-cycling through presets
    private func startAutoCycle() {
        stopAutoCycle()
        if let index = SpiralPreset.allPresets.firstIndex(where: { $0.type == spiralType }) {
            currentPresetIndex = index
        } else {
            currentPresetIndex = 0
        }
        autoCycleTask = Task {
            while !Task.isCancelled && autoCycleEnabled {
                try? await Task.sleep(for: .seconds(autoCycleIntervalSeconds))
                if !Task.isCancelled && autoCycleEnabled {
                    await MainActor.run {
                        nextPreset()
                    }
                }
            }
        }
    }
    /// Stop auto-cycling
    private func stopAutoCycle() {
        autoCycleTask?.cancel()
        autoCycleTask = nil
    }
    /// Cycle to next preset
    public func nextPreset() {
        let allPresets = SpiralPreset.allPresets
        currentPresetIndex = (currentPresetIndex + 1) % allPresets.count
        loadPreset(allPresets[currentPresetIndex])
    }
    /// Cycle to previous preset
    public func previousPreset() {
        let allPresets = SpiralPreset.allPresets
        currentPresetIndex = (currentPresetIndex - 1 + allPresets.count) % allPresets.count
        loadPreset(allPresets[currentPresetIndex])
    }
    /// Update dim mode based on viewing time
    private func updateDimMode() {
        guard dimModeEnabled else {
            if isDimmed {
                resetDimMode()
            }
            return
        }
        let viewingTime = Date().timeIntervalSince(viewingStartTime)
        if viewingTime >= dimModeDelaySeconds && !isDimmed {
            isDimmed = true
            withAnimation(.easeInOut(duration: 2.0)) {
                currentBrightness = dimModeBrightness
            }
        }
    }
    /// Reset dim mode (e.g., on user interaction)
    public func resetDimMode() {
        viewingStartTime = Date()
        isDimmed = false
        withAnimation(.easeInOut(duration: 0.5)) {
            currentBrightness = 1.0
        }
    }
    /// Called when user interacts - resets dim timer
    public func userDidInteract() {
        resetDimMode()
    }
    /// Clean up resources when view disappears
    public func cleanup() {
        stopAutoCycle()
    }
}

public final class WatchSpiralViewModel {
    private enum Keys {
        static let presetIndex = "watchPresetIndex"
        static let colorPreset = "watchColorPreset"
        static let lineStyle = "watchLineStyle"
        static let zoom = "watchZoom"
    }
    private let defaults = UserDefaults.standard
    public var spiralType: SpiralType = .archimedean {
        didSet {
            zoom = spiralType.defaultZoom
        }
    }
    public var spinRate: Double = 0.5
    public var tightness: Double = 3.0
    public var stepSize: Double = 0.1
    public var numSteps: Int = 200  // Reduced for watch performance
    public var colorPreset: ColorPreset = .rainbow {
        didSet { saveState() }
    }
    public var lineStyle: LineStyle = .solid {
        didSet { saveState() }
    }
    public var zoom: Double = 1.0 {
        didSet { saveState() }
    }
    public var time: Double = 0
    public var isPaused: Bool = false
    private let viewportScale: Double = 0.5
    /// Current parameters as a struct for spiral generation
    public var params: SpiralParams {
        SpiralParams(
            type: spiralType,
            tightness: tightness,
            spinRate: spinRate,
            stepSize: stepSize,
            numSteps: numSteps,
            time: time,
            viewportScale: viewportScale,
            zoom: zoom,
            panX: 0,
            panY: 0,
            colorPreset: colorPreset,
            lineStyle: lineStyle,
            backgroundTheme: .dark,
            performanceMode: true,  // Always use performance mode on watch
            lineThicknessVariation: false,
            isPaused: isPaused
        )
    }
    /// Generate spiral points for current parameters
    public var spiralPoints: SpiralPoints {
        SpiralGenerator.generate(params: params)
    }
    /// Colors for the current preset
    public var colors: [Color] {
        colorPreset.colors
    }
    /// Glow color
    public var glowColor: Color {
        colors.count > 2 ? colors[2] : colors[0]
    }
    /// Background color
    public var backgroundColor: Color {
        Color.black
    }
    public init() {
        loadState()
    }
    private func saveState() {
        defaults.set(currentPresetIndex, forKey: Keys.presetIndex)
        defaults.set(colorPreset.rawValue, forKey: Keys.colorPreset)
        defaults.set(lineStyle.rawValue, forKey: Keys.lineStyle)
        defaults.set(zoom, forKey: Keys.zoom)
    }
    private func loadState() {
        let savedIndex = defaults.integer(forKey: Keys.presetIndex)
        currentPresetIndex = min(savedIndex, SpiralPreset.allPresets.count - 1)
        let preset = SpiralPreset.allPresets[currentPresetIndex]
        spiralType = preset.type
        tightness = preset.tightness
        spinRate = preset.spinRate
        stepSize = preset.stepSize
        numSteps = min(preset.numSteps, 300)
        if let savedColor = defaults.string(forKey: Keys.colorPreset),
           let color = ColorPreset(rawValue: savedColor) {
            colorPreset = color
        } else {
            colorPreset = preset.colorPreset
        }
        if let savedStyle = defaults.string(forKey: Keys.lineStyle),
           let style = LineStyle(rawValue: savedStyle) {
            lineStyle = style
        } else {
            lineStyle = preset.lineStyle
        }
        let savedZoom = defaults.double(forKey: Keys.zoom)
        zoom = savedZoom > 0 ? savedZoom : preset.zoom
    }
    /// Toggle play/pause
    public func togglePause() {
        isPaused.toggle()
        WKInterfaceDevice.current().play(.click)
    }
    /// Reset zoom to default
    public func resetZoom() {
        zoom = 1.0
        WKInterfaceDevice.current().play(.click)
    }
    /// Cycle to next spiral type
    public func nextSpiralType() {
        let allTypes = SpiralType.allCases
        if let currentIndex = allTypes.firstIndex(of: spiralType) {
            let nextIndex = (currentIndex + 1) % allTypes.count
            spiralType = allTypes[nextIndex]
        }
        WKInterfaceDevice.current().play(.click)
    }
    /// Cycle to next color preset
    public func nextColorPreset() {
        let allPresets = ColorPreset.allCases
        if let currentIndex = allPresets.firstIndex(of: colorPreset) {
            let nextIndex = (currentIndex + 1) % allPresets.count
            colorPreset = allPresets[nextIndex]
        }
        WKInterfaceDevice.current().play(.click)
    }
    /// Load a preset
    public func loadPreset(_ preset: SpiralPreset) {
        spiralType = preset.type
        tightness = preset.tightness
        spinRate = preset.spinRate
        stepSize = preset.stepSize
        numSteps = min(preset.numSteps, 300)
        colorPreset = preset.colorPreset
        lineStyle = preset.lineStyle
        zoom = preset.zoom
        currentPresetIndex = SpiralPreset.allPresets.firstIndex(where: { $0.id == preset.id }) ?? 0
        saveState()
        WKInterfaceDevice.current().play(.success)
    }
    private var currentPresetIndex: Int = 0 {
        didSet { saveState() }
    }
    /// Load the next preset (swipe left)
    public func nextPreset() {
        let allPresets = SpiralPreset.allPresets
        currentPresetIndex = (currentPresetIndex + 1) % allPresets.count
        loadPresetAtCurrentIndex()
    }
    /// Load the previous preset (swipe right)
    public func previousPreset() {
        let allPresets = SpiralPreset.allPresets
        currentPresetIndex = (currentPresetIndex - 1 + allPresets.count) % allPresets.count
        loadPresetAtCurrentIndex()
    }
    private func loadPresetAtCurrentIndex() {
        let preset = SpiralPreset.allPresets[currentPresetIndex]
        spiralType = preset.type
        tightness = preset.tightness
        spinRate = preset.spinRate
        stepSize = preset.stepSize
        numSteps = min(preset.numSteps, 300)
        colorPreset = preset.colorPreset
        lineStyle = preset.lineStyle
        zoom = preset.zoom
        WKInterfaceDevice.current().play(.click)
    }
    /// Current preset name for display
    public var currentPresetName: String {
        SpiralPreset.allPresets[currentPresetIndex].name
    }
    /// Increment time for animation
    public func incrementTime(delta: Double) {
        guard !isPaused else { return }
        time += delta
    }
}
